  /* ── Fleet Tier Definitions (multi-spaceship collaboration packages) ── */
  const _FLEET_TIERS = {
    'squadron':  { name:'SQUADRON',  color:'#06b6d4', badge:'SQUADRON',  nodeCount:4 },
    'fleet':   { name:'FLEET',   color:'#8b5cf6', badge:'FLEET',   nodeCount:7 },
    'armada':  { name:'ARMADA',  color:'#ef4444', badge:'ARMADA',   nodeCount:11 }
  };

  /* ── Constellation Art (neural-network animation for fleet cards) ── */
  function _constellationArt(fleetTier, serial) {
    const tier = _FLEET_TIERS[fleetTier] || _FLEET_TIERS['squadron'];
    const color = tier.color;
    const n = tier.nodeCount;
    if (!serial) serial = _serialHash(fleetTier, 30);

    // ── Node positions (distributed around center) ──
    const positions = [];
    for (let i = 0; i < n; i++) {
      const angle = (i / n) * Math.PI * 2 + 0.3;
      const rx = 55 + (i % 3) * 12;
      const ry = 32 + (i % 2) * 10;
      positions.push({ x: Math.round(100 + Math.cos(angle) * rx), y: Math.round(60 + Math.sin(angle) * ry) });
    }

    // ── Connection pairs (nodes within distance 85) ──
    const conns = [];
    for (let i = 0; i < n; i++) {
      for (let j = i + 1; j < n; j++) {
        const dx = positions[i].x - positions[j].x, dy = positions[i].y - positions[j].y;
        if (Math.sqrt(dx * dx + dy * dy) < 85) conns.push([i, j]);
      }
    }

    const dotColors = ['#f43f5e','#f97316','#eab308','#22c55e','#14b8a6','#06b6d4',
                       '#3b82f6','#6366f1','#a855f7','#ec4899','#84cc16','#fb923c'];
    const localOrbitR = 16;

    // ── Background grid ──
    let svg = `<svg viewBox="0 0 200 120" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:100%">
      <line x1="10" y1="20" x2="190" y2="20" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="10" y1="40" x2="190" y2="40" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="10" y1="60" x2="190" y2="60" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="10" y1="80" x2="190" y2="80" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="10" y1="100" x2="190" y2="100" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="30" y1="5" x2="30" y2="115" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="60" y1="5" x2="60" y2="115" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="90" y1="5" x2="90" y2="115" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="120" y1="5" x2="120" y2="115" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="150" y1="5" x2="150" y2="115" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>
      <line x1="180" y1="5" x2="180" y2="115" stroke="#3b82f6" stroke-width="0.5" opacity="0.07"/>`;

    // ── Center hub ──
    svg += `<circle cx="100" cy="60" r="5" fill="${color}" opacity="0.3"/>`;

    // ── Neural network connection lines ──
    conns.forEach(pair => {
      const a = positions[pair[0]], b = positions[pair[1]];
      svg += `<line x1="${a.x}" y1="${a.y}" x2="${b.x}" y2="${b.y}" stroke="${color}" stroke-width="0.6" opacity="0.12"/>`;
    });

    // ── Spoke lines (hub to each node) ──
    positions.forEach(p => {
      svg += `<line x1="100" y1="60" x2="${p.x}" y2="${p.y}" stroke="${color}" stroke-width="0.8" opacity="0.1"/>`;
    });

    // ── Static diamond nodes ──
    positions.forEach((p, i) => {
      const s = 10;
      const diamond = `${p.x},${p.y - s} ${p.x + s},${p.y} ${p.x},${p.y + s} ${p.x - s},${p.y}`;
      svg += `<polygon points="${diamond}" fill="${color}" opacity="0.08"/>`;
      svg += `<polygon points="${diamond}" fill="none" stroke="${color}" stroke-width="1.2" stroke-dasharray="5,3" opacity="0.6"/>`;
      svg += `<text x="${p.x}" y="${p.y}" text-anchor="middle" dominant-baseline="central" fill="${color}" font-size="7" font-weight="600" opacity="0.5">&#9670;</text>`;
    });

    // ── Local orbit dots (one per node) ──
    positions.forEach((p, i) => {
      const spd = serial.speeds[i] || 0;
      const dur = 20 - (spd * 1.5);
      const dotR = 1.5 + (spd * 0.12);
      const dc = dotColors[i % dotColors.length];
      svg += `<circle cx="${p.x + localOrbitR}" cy="${p.y}" r="${dotR + 1.5}" fill="${dc}" opacity="0.2"><animateTransform attributeName="transform" type="rotate" from="0 ${p.x} ${p.y}" to="360 ${p.x} ${p.y}" dur="${dur}s" repeatCount="indefinite"/></circle>`;
      svg += `<circle cx="${p.x + localOrbitR}" cy="${p.y}" r="${dotR}" fill="${dc}" opacity="0.85"><animateTransform attributeName="transform" type="rotate" from="0 ${p.x} ${p.y}" to="360 ${p.x} ${p.y}" dur="${dur}s" repeatCount="indefinite"/></circle>`;
    });

    // ── Traveling dots between connections (neural data flow) ──
    const travelSpeeds = serial.speeds.slice(n);
    conns.forEach((pair, ci) => {
      const a = positions[pair[0]], b = positions[pair[1]];
      const spd = travelSpeeds[ci % travelSpeeds.length] || 3;
      const dur = 6 + (9 - spd) * 1.2;
      const dotR = 1.2 + (spd * 0.08);
      const dc = dotColors[(ci + n) % dotColors.length];
      const delay = ((ci * 0.7) % dur).toFixed(1);
      svg += `<circle r="${dotR + 1}" fill="${dc}" opacity="0.2"><animate attributeName="cx" values="${a.x};${b.x};${a.x}" dur="${dur}s" begin="${delay}s" repeatCount="indefinite" calcMode="spline" keySplines="0.4 0 0.6 1;0.4 0 0.6 1"/><animate attributeName="cy" values="${a.y};${b.y};${a.y}" dur="${dur}s" begin="${delay}s" repeatCount="indefinite" calcMode="spline" keySplines="0.4 0 0.6 1;0.4 0 0.6 1"/></circle>`;
      svg += `<circle r="${dotR}" fill="${dc}" opacity="0.7"><animate attributeName="cx" values="${a.x};${b.x};${a.x}" dur="${dur}s" begin="${delay}s" repeatCount="indefinite" calcMode="spline" keySplines="0.4 0 0.6 1;0.4 0 0.6 1"/><animate attributeName="cy" values="${a.y};${b.y};${a.y}" dur="${dur}s" begin="${delay}s" repeatCount="indefinite" calcMode="spline" keySplines="0.4 0 0.6 1;0.4 0 0.6 1"/></circle>`;
    });

    svg += '</svg>';
    return svg;
  }

  /* ── Palette Art Generator (color swatches for theme cards) ── */
  function _paletteArt(name, previewColors, serial) {
    if (!serial) serial = _serialHash(name || 'theme');
    const accent = previewColors[1] || '#ffffff';
    const accent2 = previewColors[2] || '#888888';
    const bg = previewColors[0] || '#080808';

    // Derive lighter/darker variants from accent
    const swatchColors = [accent, accent2, bg, accent + 'aa', accent2 + '88'];

    // 6 orbiting dots
    const dotColors = ['#f43f5e','#f97316','#eab308','#22c55e','#14b8a6','#06b6d4'];
    let dots = '';
    for (let i = 0; i < 6; i++) {
      const spd = serial.speeds[i] || 3;
      const dur = 22 - (spd * 2);
      const startAngle = i * 60;
      const r = 1.5 + (spd * 0.15);
      const dc = dotColors[i];
      dots += `<circle cx="100" cy="22" r="${r + 1.5}" fill="${dc}" opacity="0.2"><animateTransform attributeName="transform" type="rotate" from="${startAngle} 100 60" to="${startAngle + 360} 100 60" dur="${dur}s" repeatCount="indefinite"/></circle>`;
      dots += `<circle cx="100" cy="22" r="${r}" fill="${dc}" opacity="0.85"><animateTransform attributeName="transform" type="rotate" from="${startAngle} 100 60" to="${startAngle + 360} 100 60" dur="${dur}s" repeatCount="indefinite"/></circle>`;
    }

    // 5 color swatches in an arc
    let swatches = '';
    const arcCenters = [{x:40,y:45},{x:65,y:32},{x:100,y:28},{x:135,y:32},{x:160,y:45}];
    arcCenters.forEach((pos, i) => {
      const c = swatchColors[i] || accent;
      swatches += `<circle cx="${pos.x}" cy="${pos.y}" r="10" fill="${c}" opacity="0.85" stroke="${accent}" stroke-width="0.8" stroke-opacity="0.3"/>`;
    });

    return `<svg viewBox="0 0 200 120" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:100%">
      <line x1="0" y1="30" x2="200" y2="30" stroke="${accent}" stroke-width="0.5" opacity="0.08"/>
      <line x1="0" y1="60" x2="200" y2="60" stroke="${accent}" stroke-width="0.5" opacity="0.08"/>
      <line x1="0" y1="90" x2="200" y2="90" stroke="${accent}" stroke-width="0.5" opacity="0.08"/>
      <line x1="50" y1="0" x2="50" y2="120" stroke="${accent}" stroke-width="0.5" opacity="0.08"/>
      <line x1="100" y1="0" x2="100" y2="120" stroke="${accent}" stroke-width="0.5" opacity="0.08"/>
      <line x1="150" y1="0" x2="150" y2="120" stroke="${accent}" stroke-width="0.5" opacity="0.08"/>
      <circle cx="100" cy="60" r="38" fill="none" stroke="${accent}" stroke-width="2.5" opacity="0.15"/>
      ${dots}
      <circle cx="100" cy="60" r="28" fill="${accent}" opacity="0.12"/>
      <circle cx="100" cy="60" r="26" fill="none" stroke="${accent}" stroke-width="1.5" opacity="0.4"/>
      ${swatches}
      <text x="100" y="60" text-anchor="middle" dominant-baseline="central" fill="${accent}" font-family="var(--font-h, Inter, sans-serif)" font-size="20" font-weight="700" letter-spacing="1" opacity="0.9">Aa</text>
    </svg>`;
  }

